import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Button,
  Typography,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Chip,
  Stack,
  Alert,
  Snackbar,
  CircularProgress,
  LinearProgress,
  useTheme
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  DarkMode as DarkModeIcon,
  LightMode as LightModeIcon,
  OpenInNew as OpenInNewIcon
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import { getRules, createRule, updateRule, deleteRule } from '../services/api';

const Rules = ({ mode, setMode, onDashboardClick }) => {
  const theme = useTheme();
  const [rules, setRules] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);
  const [selectedRule, setSelectedRule] = useState(null);
  const [editRule, setEditRule] = useState({
    name: '',
    type: '',
    nodeList: [],
    direct: false
  });

  useEffect(() => {
    fetchRules();
  }, []);

  const fetchRules = async () => {
    try {
      setLoading(true);
      const data = await getRules();
      setRules(data);
    } catch (err) {
      setError('Failed to load rules');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenDialog = (rule = null) => {
    if (rule) {
      setSelectedRule(rule);
      setEditRule(rule);
    } else {
      setSelectedRule(null);
      setEditRule({
        name: '',
        type: '',
        nodeList: [],
        direct: false
      });
    }
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
    setSelectedRule(null);
    setEditRule({
      name: '',
      type: '',
      nodeList: [],
      direct: false
    });
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      if (selectedRule) {
        await updateRule(selectedRule.id, editRule);
      } else {
        await createRule(editRule);
      }
      await fetchRules();
      setSuccess(true);
      handleCloseDialog();
    } catch (err) {
      setError('Failed to save rule');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      setLoading(true);
      await deleteRule(id);
      await fetchRules();
      setSuccess(true);
    } catch (err) {
      setError('Failed to delete rule');
    } finally {
      setLoading(false);
    }
  };

  const handleCopy = (rule) => {
    const newRule = { ...rule, name: `${rule.name} (Copy)` };
    handleOpenDialog(newRule);
  };

  const cardStyle = {
    height: '100%',
    transition: 'all 0.2s ease-in-out',
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(145deg, rgba(26,35,126,0.7), rgba(49,27,146,0.7))'
      : 'linear-gradient(145deg, rgba(255,255,255,0.9), rgba(255,255,255,0.95))',
    backdropFilter: 'blur(10px)',
    border: theme.palette.mode === 'dark'
      ? '1px solid rgba(255,255,255,0.1)'
      : '1px solid rgba(255,255,255,0.5)',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 12px 0 rgba(0,0,0,0.3), 0 2px 4px -1px rgba(0,0,0,0.4)'
      : '0 4px 12px 0 rgba(31,38,135,0.15), 0 2px 4px -1px rgba(31,38,135,0.2)',
    '&:hover': {
      transform: 'translateY(-2px)',
      boxShadow: theme.palette.mode === 'dark'
        ? '0 6px 16px 0 rgba(0,0,0,0.4), 0 3px 6px -2px rgba(0,0,0,0.5)'
        : '0 6px 16px 0 rgba(31,38,135,0.25), 0 3px 6px -2px rgba(31,38,135,0.3)',
    }
  };

  const headerCardStyle = {
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(90deg, #1a237e 0%, #311b92 100%)'
      : 'linear-gradient(90deg, #3949ab 0%, #5e35b1 100%)',
    color: '#fff',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 12px 0 rgba(0,0,0,0.3), 0 2px 4px -1px rgba(0,0,0,0.4)'
      : '0 4px 12px 0 rgba(31,38,135,0.15), 0 2px 4px -1px rgba(31,38,135,0.2)',
    mb: 1.5,
    backdropFilter: 'blur(10px)',
    border: '1px solid rgba(255,255,255,0.1)',
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: {
        duration: 0.3,
      }
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card sx={headerCardStyle}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                规则管理
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Stack direction="row" spacing={1}>
              <IconButton
                size="small"
                onClick={onDashboardClick}
                sx={{ 
                  color: 'rgba(255,255,255,0.8)',
                  '&:hover': { 
                    color: '#fff',
                    backgroundColor: 'rgba(255,255,255,0.1)' 
                  }
                }}
              >
                <OpenInNewIcon fontSize="small" />
              </IconButton>
              <IconButton
                size="small"
                onClick={() => setMode(mode === 'dark' ? 'light' : 'dark')}
                sx={{ 
                  color: 'rgba(255,255,255,0.8)',
                  '&:hover': { 
                    color: '#fff',
                    backgroundColor: 'rgba(255,255,255,0.1)' 
                  }
                }}
              >
                {mode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
              </IconButton>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <motion.div
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <Grid container spacing={1.5}>
          {rules.map((rule) => (
            <Grid item xs={12} sm={6} lg={4} key={rule.id}>
              <motion.div variants={cardVariants}>
                <Card sx={cardStyle}>
                  <CardContent>
                    <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
                      <Typography variant="h6">{rule.name}</Typography>
                      <Stack direction="row" spacing={0.5}>
                        <IconButton 
                          size="small" 
                          onClick={() => handleOpenDialog(rule)}
                          sx={{
                            color: 'text.secondary',
                            '&:hover': {
                              color: 'primary.main',
                              backgroundColor: 'action.hover',
                            },
                          }}
                        >
                          <EditIcon fontSize="small" />
                        </IconButton>
                        <IconButton 
                          size="small" 
                          onClick={() => handleDelete(rule.id)}
                          sx={{
                            color: 'text.secondary',
                            '&:hover': {
                              color: 'error.main',
                              backgroundColor: 'action.hover',
                            },
                          }}
                        >
                          <DeleteIcon fontSize="small" />
                        </IconButton>
                      </Stack>
                    </Box>
                    <Stack direction="row" spacing={1} sx={{ mb: 1.5 }}>
                      <Chip 
                        label={rule.type} 
                        color="primary" 
                        size="small"
                        sx={{
                          borderRadius: 1,
                          '& .MuiChip-label': {
                            px: 1,
                          },
                        }}
                      />
                      <Chip 
                        label={rule.direct ? "直连" : "代理"} 
                        color={rule.direct ? "success" : "warning"} 
                        size="small"
                        sx={{
                          borderRadius: 1,
                          '& .MuiChip-label': {
                            px: 1,
                          },
                        }}
                      />
                    </Stack>
                  </CardContent>
                </Card>
              </motion.div>
            </Grid>
          ))}
        </Grid>
      </motion.div>

      <Box sx={{ position: 'fixed', right: 24, bottom: 24 }}>
        <Button
          variant="contained"
          size="large"
          startIcon={<AddIcon />}
          onClick={() => handleOpenDialog()}
          sx={{
            borderRadius: 2,
            px: 3,
            boxShadow: (theme) =>
              theme.palette.mode === 'dark'
                ? '0 4px 12px 0 rgba(0,0,0,0.4)'
                : '0 4px 12px 0 rgba(31,38,135,0.2)',
            '&:hover': {
              boxShadow: (theme) =>
                theme.palette.mode === 'dark'
                  ? '0 6px 16px 0 rgba(0,0,0,0.5)'
                  : '0 6px 16px 0 rgba(31,38,135,0.3)',
            },
          }}
        >
          添加规则
        </Button>
      </Box>

      <Dialog 
        open={openDialog} 
        onClose={handleCloseDialog} 
        maxWidth="sm" 
        fullWidth
        PaperProps={{
          sx: {
            borderRadius: 2,
            boxShadow: theme.palette.mode === 'dark'
              ? '0 8px 24px 0 rgba(0,0,0,0.4)'
              : '0 8px 24px 0 rgba(31,38,135,0.2)',
          }
        }}
      >
        <DialogTitle>
          {selectedRule ? '编辑规则' : '添加规则'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="规则名称"
                  value={editRule.name}
                  onChange={(e) => setEditRule({ ...editRule, name: e.target.value })}
                  size="small"
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      '&:hover fieldset': {
                        borderColor: 'primary.main',
                      },
                    },
                  }}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="规则类型"
                  value={editRule.type}
                  onChange={(e) => setEditRule({ ...editRule, type: e.target.value })}
                  size="small"
                  sx={{
                    '& .MuiOutlinedInput-root': {
                      '&:hover fieldset': {
                        borderColor: 'primary.main',
                      },
                    },
                  }}
                />
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button 
            onClick={handleCloseDialog} 
            size="small"
            sx={{
              color: 'text.secondary',
              '&:hover': {
                backgroundColor: 'action.hover',
              },
            }}
          >
            取消
          </Button>
          <Button 
            variant="contained" 
            onClick={handleSave}
            disabled={loading}
            size="small"
            sx={{
              px: 3,
              boxShadow: 'none',
              '&:hover': {
                boxShadow: 'none',
              },
            }}
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default Rules;
